+@inject ISettingsService SettingsService
+
+<PageTitle>Settings</PageTitle>
+
+<div class="settings-container">
+    <!-- Left sidebar navigation -->
+    <nav class="settings-sidebar">
+        <h5 class="sidebar-title">Settings</h5>
+        <ul class="nav flex-column">
+            @foreach (var section in _sections)
+            {
+                <li class="nav-item">
+                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
+                            @onclick="() => SetActiveSection(section.Key)">
+                        <span class="section-icon">@section.Value.Icon</span>
+                        @section.Value.Label
+                    </button>
+                </li>
+            }
+        </ul>
+    </nav>
+
+    <!-- Main content area -->
+    <div class="settings-content">
+        @if (_loading)
+        {
+            <div class="text-center py-5">
+                <div class="spinner-border text-primary" role="status">
+                    <span class="visually-hidden">Loading...</span>
+                </div>
+            </div>
+        }
+        else
+        {
+            @switch (ActiveSection)
+            {
+                case "profile":
+                    @RenderProfileSection()
+                    break;
+                case "notifications":
+                    @RenderNotificationsSection()
+                    break;
+                case "security":
+                    @RenderSecuritySection()
+                    break;
+                case "appearance":
+                    @RenderAppearanceSection()
+                    break;
+            }
+        }
+    </div>
+</div>
+
+<!-- Toast notification -->
+@if (_showToast)
+{
+    <div class="settings-toast @(_toastType)" role="alert">
+        <span>@_toastMessage</span>
+        <button class="btn-close btn-close-white btn-sm" @onclick="() => _showToast = false"></button>
+    </div>
+}
+
+<!-- Session revoke confirmation modal -->
+@if (_showRevokeConfirm)
+{
+    <div class="modal-backdrop show" @onclick="() => _showRevokeConfirm = false"></div>
+    <div class="modal show d-block" tabindex="-1">
+        <div class="modal-dialog modal-dialog-centered">
+            <div class="modal-content">
+                <div class="modal-header">
+                    <h5 class="modal-title">Revoke Session</h5>
+                    <button type="button" class="btn-close" @onclick="() => _showRevokeConfirm = false"></button>
+                </div>
+                <div class="modal-body">
+                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?</p>
+                    <p class="text-muted mb-0">This will sign out that device immediately.</p>
+                </div>
+                <div class="modal-footer">
+                    <button type="button" class="btn btn-secondary" @onclick="() => _showRevokeConfirm = false">Cancel</button>
+                    <button type="button" class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_revoking">
+                        @if (_revoking)
+                        {
+                            <span class="spinner-border spinner-border-sm me-1"></span>
+                        }
+                        Revoke
+                    </button>
+                </div>
+            </div>
+        </div>
+    </div>
+}
+
+@code {
+    // ── Section definitions ──
+    private record SectionInfo(string Label, string Icon);
+
+    private readonly Dictionary<string, SectionInfo> _sections = new()
+    {
+        ["profile"] = new("Profile", "👤"),
+        ["notifications"] = new("Notifications", "🔔"),
+        ["security"] = new("Security", "🔒"),
+        ["appearance"] = new("Appearance", "🎨")
+    };
+
+    // ── Common state ──
+    private string ActiveSection { get; set; } = "profile";
+    private bool _loading = true;
+    private bool _saving;
+
+    // ── Toast state ──
+    private bool _showToast;
+    private string _toastMessage = "";
+    private string _toastType = "toast-success";
+    private CancellationTokenSource? _toastCts;
+
+    // ── Profile state ──
+    private UserProfile? _profile;
+    private UserProfile? _savedProfile;
+    private string _editDisplayName = "";
+    private string _editEmail = "";
+    private string _editBio = "";
+    private string _editAvatarUrl = "";
+
+    // ── Notification state ──
+    private bool _emailNotifications;
+    private bool _pushNotifications;
+    private bool _weeklyDigest;
+    private List<string> _allChannels = ["#general", "#random", "#off-topic", "#engineering", "#design", "#announcements"];
+    private HashSet<string> _mutedChannels = [];
+
+    // ── Security state ──
+    private SecuritySettings? _security;
+    private bool _passwordPanelOpen;
+    private string _currentPassword = "";
+    private string _newPassword = "";
+    private string _confirmPassword = "";
+    private string? _passwordError;
+    private bool _changingPassword;
+    private bool _showRevokeConfirm;
+    private ActiveSession? _sessionToRevoke;
+    private bool _revoking;
+
+    // ── Appearance state ──
+    private string _theme = "Light";
+    private string _fontSize = "Medium";
+    private string _language = "English";
+    private bool _compactMode;
+    private readonly List<string> _availableLanguages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];
+
+    // ── Lifecycle ──
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadSectionDataAsync();
+    }
+
+    private async Task LoadSectionDataAsync()
+    {
+        _loading = true;
+        try
+        {
+            switch (ActiveSection)
+            {
+                case "profile":
+                    _profile = await SettingsService.GetProfileAsync();
+                    _savedProfile = _profile;
+                    ResetProfileForm();
+                    break;
+                case "notifications":
+                    var prefs = await SettingsService.GetNotificationPrefsAsync();
+                    _emailNotifications = prefs.EmailNotifications;
+                    _pushNotifications = prefs.PushNotifications;
+                    _weeklyDigest = prefs.WeeklyDigest;
+                    _mutedChannels = [.. prefs.MutedChannels];
+                    break;
+                case "security":
+                    _security = await SettingsService.GetSecuritySettingsAsync();
+                    _passwordPanelOpen = false;
+                    ClearPasswordForm();
+                    break;
+                case "appearance":
+                    var appearance = await SettingsService.GetAppearanceAsync();
+                    _theme = appearance.Theme;
+                    _fontSize = appearance.FontSize;
+                    _language = appearance.Language;
+                    _compactMode = appearance.CompactMode;
+                    break;
+            }
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private async Task SetActiveSection(string section)
+    {
+        if (ActiveSection == section) return;
+        ActiveSection = section;
+        await LoadSectionDataAsync();
+    }
+
+    // ── Toast helpers ──
+
+    private async Task ShowToast(string message, bool success = true)
+    {
+        _toastCts?.Cancel();
+        _toastCts = new CancellationTokenSource();
+        var token = _toastCts.Token;
+
+        _toastMessage = message;
+        _toastType = success ? "toast-success" : "toast-error";
+        _showToast = true;
+        StateHasChanged();
+
+        try
+        {
+            await Task.Delay(3000, token);
+            _showToast = false;
+            StateHasChanged();
+        }
+        catch (TaskCanceledException) { }
+    }
+
+    // ── Profile logic ──
+
+    private void ResetProfileForm()
+    {
+        if (_savedProfile is null) return;
+        _editDisplayName = _savedProfile.DisplayName;
+        _editEmail = _savedProfile.Email;
+        _editBio = _savedProfile.Bio;
+        _editAvatarUrl = _savedProfile.AvatarUrl;
+    }
+
+    private bool ProfileHasChanges =>
+        _savedProfile is not null &&
+        (_editDisplayName != _savedProfile.DisplayName ||
+         _editEmail != _savedProfile.Email ||
+         _editBio != _savedProfile.Bio ||
+         _editAvatarUrl != _savedProfile.AvatarUrl);
+
+    private async Task SaveProfile()
+    {
+        _saving = true;
+        try
+        {
+            var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
+            await SettingsService.SaveProfileAsync(updated);
+            _savedProfile = updated;
+            _profile = updated;
+            await ShowToast("Profile saved successfully!");
+        }
+        catch
+        {
+            await ShowToast("Failed to save profile.", false);
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+
+    private void DiscardProfileChanges()
+    {
+        ResetProfileForm();
+    }
+
+    private RenderFragment RenderProfileSection() => __builder =>
+    {
+        <h4 class="section-heading">Profile</h4>
+        <p class="text-muted">Manage your personal information and public profile.</p>
+        <hr />
+
+        <div class="row g-4">
+            <!-- Avatar preview -->
+            <div class="col-md-4 text-center">
+                <div class="avatar-preview">
+                    @if (!string.IsNullOrWhiteSpace(_editAvatarUrl))
+                    {
+                        <img src="@_editAvatarUrl" alt="Avatar" class="avatar-img" />
+                    }
+                    else
+                    {
+                        <div class="avatar-placeholder">👤</div>
+                    }
+                </div>
+                <div class="mt-3">
+                    <label class="form-label fw-semibold">Avatar URL</label>
+                    <input type="url" class="form-control form-control-sm" @bind="_editAvatarUrl"
+                           placeholder="https://example.com/avatar.png" />
+                </div>
+            </div>
+
+            <!-- Editable fields -->
+            <div class="col-md-8">
+                <div class="mb-3">
+                    <label class="form-label fw-semibold">Display Name</label>
+                    <input type="text" class="form-control" @bind="_editDisplayName" placeholder="Your name" />
+                </div>
+                <div class="mb-3">
+                    <label class="form-label fw-semibold">Email</label>
+                    <input type="email" class="form-control" @bind="_editEmail" placeholder="you@example.com" />
+                </div>
+                <div class="mb-3">
+                    <label class="form-label fw-semibold">Bio</label>
+                    <textarea class="form-control" rows="4" @bind="_editBio" placeholder="Tell us about yourself..."></textarea>
+                </div>
+
+                <div class="d-flex gap-2">
+                    <button class="btn btn-primary" @onclick="SaveProfile" disabled="@(!ProfileHasChanges || _saving)">
+                        @if (_saving)
+                        {
+                            <span class="spinner-border spinner-border-sm me-1"></span>
+                        }
+                        Save Changes
+                    </button>
+                    <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges"
+                            disabled="@(!ProfileHasChanges)">
+                        Discard Changes
+                    </button>
+                </div>
+            </div>
+        </div>
+    };
+
+    // ── Notification logic ──
+
+    private void ToggleMutedChannel(string channel, bool muted)
+    {
+        if (muted)
+            _mutedChannels.Add(channel);
+        else
+            _mutedChannels.Remove(channel);
+    }
+
+    private async Task SaveNotifications()
+    {
+        _saving = true;
+        try
+        {
+            var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
+            await SettingsService.SaveNotificationPrefsAsync(prefs);
+            await ShowToast("Notification preferences saved!");
+        }
+        catch
+        {
+            await ShowToast("Failed to save preferences.", false);
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+
+    private RenderFragment RenderNotificationsSection() => __builder =>
+    {
+        <h4 class="section-heading">Notifications</h4>
+        <p class="text-muted">Control how and when you receive notifications.</p>
+        <hr />
+
+        <div class="mb-4">
+            <h6 class="fw-semibold mb-3">Notification Channels</h6>
+            <div class="setting-row">
+                <div>
+                    <div class="fw-semibold">Email Notifications</div>
+                    <small class="text-muted">Receive notifications via email</small>
+                </div>
+                <div class="form-check form-switch">
+                    <input class="form-check-input toggle-switch" type="checkbox" role="switch"
+                           checked="@_emailNotifications"
+                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
+                </div>
+            </div>
+            <div class="setting-row">
+                <div>
+                    <div class="fw-semibold">Push Notifications</div>
+                    <small class="text-muted">Receive push notifications on your devices</small>
+                </div>
+                <div class="form-check form-switch">
+                    <input class="form-check-input toggle-switch" type="checkbox" role="switch"
+                           checked="@_pushNotifications"
+                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
+                </div>
+            </div>
+            <div class="setting-row">
+                <div>
+                    <div class="fw-semibold">Weekly Digest</div>
+                    <small class="text-muted">Get a weekly summary of activity</small>
+                </div>
+                <div class="form-check form-switch">
+                    <input class="form-check-input toggle-switch" type="checkbox" role="switch"
+                           checked="@_weeklyDigest"
+                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
+                </div>
+            </div>
+        </div>
+
+        <div class="mb-4">
+            <h6 class="fw-semibold mb-3">Muted Channels</h6>
+            <p class="text-muted small">Select channels to mute. You won't receive notifications from muted channels.</p>
+            <div class="channel-list">
+                @foreach (var channel in _allChannels)
+                {
+                    var isMuted = _mutedChannels.Contains(channel);
+                    <div class="form-check channel-item">
+                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
+                               checked="@isMuted"
+                               @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
+                        <label class="form-check-label" for="@($"ch-{channel}")">
+                            @channel
+                            @if (isMuted)
+                            {
+                                <span class="badge bg-secondary ms-2">Muted</span>
+                            }
+                        </label>
+                    </div>
+                }
+            </div>
+        </div>
+
+        <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
+            @if (_saving)
+            {
+                <span class="spinner-border spinner-border-sm me-1"></span>
+            }
+            Save Preferences
+        </button>
+    };
+
+    // ── Security logic ──
+
+    private void ClearPasswordForm()
+    {
+        _currentPassword = "";
+        _newPassword = "";
+        _confirmPassword = "";
+        _passwordError = null;
+    }
+
+    private async Task ChangePassword()
+    {
+        _passwordError = null;
+
+        if (string.IsNullOrWhiteSpace(_currentPassword))
+        {
+            _passwordError = "Current password is required.";
+            return;
+        }
+        if (_newPassword.Length < 8)
+        {
+            _passwordError = "New password must be at least 8 characters.";
+            return;
+        }
+        if (_newPassword != _confirmPassword)
+        {
+            _passwordError = "Passwords do not match.";
+            return;
+        }
+
+        _changingPassword = true;
+        try
+        {
+            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
+            _security = await SettingsService.GetSecuritySettingsAsync();
+            ClearPasswordForm();
+            _passwordPanelOpen = false;
+            await ShowToast("Password updated successfully!");
+        }
+        catch
+        {
+            _passwordError = "Failed to change password. Please check your current password.";
+        }
+        finally
+        {
+            _changingPassword = false;
+        }
+    }
+
+    private void RequestRevokeSession(ActiveSession session)
+    {
+        _sessionToRevoke = session;
+        _showRevokeConfirm = true;
+    }
+
+    private async Task ConfirmRevokeSession()
+    {
+        if (_sessionToRevoke is null) return;
+        _revoking = true;
+        try
+        {
+            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
+            _security = await SettingsService.GetSecuritySettingsAsync();
+            await ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
+        }
+        catch
+        {
+            await ShowToast("Failed to revoke session.", false);
+        }
+        finally
+        {
+            _revoking = false;
+            _showRevokeConfirm = false;
+            _sessionToRevoke = null;
+        }
+    }
+
+    private RenderFragment RenderSecuritySection() => __builder =>
+    {
+        <h4 class="section-heading">Security</h4>
+        <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>
+        <hr />
+
+        <!-- Change Password expandable panel -->
+        <div class="card mb-4">
+            <div class="card-header d-flex justify-content-between align-items-center clickable"
+                 @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
+                <span class="fw-semibold">Change Password</span>
+                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
+            </div>
+            @if (_passwordPanelOpen)
+            {
+                <div class="card-body">
+                    @if (_security?.LastPasswordChange is not null)
+                    {
+                        <p class="text-muted small mb-3">
+                            Last changed: @_security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
+                        </p>
+                    }
+
+                    @if (_passwordError is not null)
+                    {
+                        <div class="alert alert-danger py-2">@_passwordError</div>
+                    }
+
+                    <div class="mb-3">
+                        <label class="form-label fw-semibold">Current Password</label>
+                        <input type="password" class="form-control" @bind="_currentPassword" />
+                    </div>
+                    <div class="mb-3">
+                        <label class="form-label fw-semibold">New Password</label>
+                        <input type="password" class="form-control" @bind="_newPassword" />
+                        <div class="form-text">Minimum 8 characters</div>
+                    </div>
+                    <div class="mb-3">
+                        <label class="form-label fw-semibold">Confirm New Password</label>
+                        <input type="password" class="form-control" @bind="_confirmPassword" />
+                    </div>
+                    <button class="btn btn-primary" @onclick="ChangePassword" disabled="@_changingPassword">
+                        @if (_changingPassword)
+                        {
+                            <span class="spinner-border spinner-border-sm me-1"></span>
+                        }
+                        Update Password
+                    </button>
+                </div>
+            }
+        </div>
+
+        <!-- Two-Factor Authentication -->
+        <div class="card mb-4">
+            <div class="card-body">
+                <div class="setting-row mb-0">
+                    <div>
+                        <div class="fw-semibold">Two-Factor Authentication</div>
+                        <small class="text-muted">Add an extra layer of security to your account</small>
+                    </div>
+                    <div class="d-flex align-items-center gap-2">
+                        <span class="badge @(_security?.TwoFactorEnabled == true ? "bg-success" : "bg-secondary")">
+                            @(_security?.TwoFactorEnabled == true ? "Enabled" : "Disabled")
+                        </span>
+                        <div class="form-check form-switch mb-0">
+                            <input class="form-check-input toggle-switch" type="checkbox" role="switch"
+                                   checked="@(_security?.TwoFactorEnabled ?? false)" disabled />
+                        </div>
+                    </div>
+                </div>
+            </div>
+        </div>
+
+        <!-- Active Sessions -->
+        <div class="card">
+            <div class="card-header fw-semibold">Active Sessions</div>
+            <div class="card-body p-0">
+                @if (_security?.Sessions is { Count: > 0 })
+                {
+                    <div class="table-responsive">
+                        <table class="table table-hover mb-0">
+                            <thead class="table-light">
+                                <tr>
+                                    <th>Device</th>
+                                    <th>Location</th>
+                                    <th>Last Active</th>
+                                    <th class="text-end">Action</th>
+                                </tr>
+                            </thead>
+                            <tbody>
+                                @foreach (var session in _security.Sessions)
+                                {
+                                    var isFirst = session == _security.Sessions[0];
+                                    <tr>
+                                        <td>
+                                            @session.Device
+                                            @if (isFirst)
+                                            {
+                                                <span class="badge bg-primary ms-2">Current</span>
+                                            }
+                                        </td>
+                                        <td>@session.Location</td>
+                                        <td>@FormatLastActive(session.LastActive)</td>
+                                        <td class="text-end">
+                                            @if (!isFirst)
+                                            {
+                                                <button class="btn btn-outline-danger btn-sm"
+                                                        @onclick="() => RequestRevokeSession(session)">
+                                                    Revoke
+                                                </button>
+                                            }
+                                        </td>
+                                    </tr>
+                                }
+                            </tbody>
+                        </table>
+                    </div>
+                }
+                else
+                {
+                    <p class="text-muted p-3 mb-0">No active sessions.</p>
+                }
+            </div>
+        </div>
+    };
+
+    private static string FormatLastActive(DateTime lastActive)
+    {
+        var diff = DateTime.UtcNow - lastActive;
+        if (diff.TotalMinutes < 1) return "Just now";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
+        return $"{(int)diff.TotalDays}d ago";
+    }
+
+    // ── Appearance logic ──
+
+    private async Task SaveAppearance()
+    {
+        _saving = true;
+        try
+        {
+            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+            await SettingsService.SaveAppearanceAsync(settings);
+            await ShowToast("Appearance settings saved!");
+        }
+        catch
+        {
+            await ShowToast("Failed to save appearance settings.", false);
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+
+    private string PreviewFontSize => _fontSize switch
+    {
+        "Small" => "0.85rem",
+        "Large" => "1.15rem",
+        _ => "1rem"
+    };
+
+    private string PreviewBg => _theme switch
+    {
+        "Dark" => "#1e1e2e",
+        _ => "#ffffff"
+    };
+
+    private string PreviewText => _theme switch
+    {
+        "Dark" => "#cdd6f4",
+        _ => "#212529"
+    };
+
+    private string PreviewMuted => _theme switch
+    {
+        "Dark" => "#6c7086",
+        _ => "#6c757d"
+    };
+
+    private string PreviewBorder => _theme switch
+    {
+        "Dark" => "#45475a",
+        _ => "#dee2e6"
+    };
+
+    private RenderFragment RenderAppearanceSection() => __builder =>
+    {
+        <h4 class="section-heading">Appearance</h4>
+        <p class="text-muted">Customize the look and feel of the application.</p>
+        <hr />
+
+        <div class="row g-4">
+            <div class="col-md-6">
+                <!-- Theme selector -->
+                <div class="mb-4">
+                    <h6 class="fw-semibold mb-3">Theme</h6>
+                    @foreach (var t in new[] { "Light", "Dark", "System" })
+                    {
+                        <div class="form-check">
+                            <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
+                                   value="@t" checked="@(_theme == t)"
+                                   @onchange="() => _theme = t" />
+                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
+                        </div>
+                    }
+                </div>
+
+                <!-- Font size selector -->
+                <div class="mb-4">
+                    <h6 class="fw-semibold mb-3">Font Size</h6>
+                    @foreach (var fs in new[] { "Small", "Medium", "Large" })
+                    {
+                        <div class="form-check">
+                            <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{fs}")"
+                                   value="@fs" checked="@(_fontSize == fs)"
+                                   @onchange="() => _fontSize = fs" />
+                            <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
+                        </div>
+                    }
+                </div>
+
+                <!-- Language dropdown -->
